+    private ValidationMessageStore? messageStore;
+
+    private bool showStep2;
+    private bool availabilityChecked;
+    private bool bookingConfirmed;
+    private List<string> doctors = new();
+    private List<string> timeSlots = new();
+    private Dictionary<string, string> serverErrors = new();
+
+    protected override async Task OnInitializedAsync()
+    {
+        doctors = await AppointmentService.GetDoctorsAsync();
+    }
+
+    private void ProceedToStep2()
+    {
+        editContext = new EditContext(Model);
+        messageStore = new ValidationMessageStore(editContext);
+
+        // Validate step 1 fields manually
+        var isValid = true;
+
+        if (string.IsNullOrWhiteSpace(Model.PatientName))
+            isValid = false;
+        if (string.IsNullOrWhiteSpace(Model.Email) || !Model.Email.Contains('@'))
+            isValid = false;
+        if (string.IsNullOrWhiteSpace(Model.Phone))
+            isValid = false;
+        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
+            isValid = false;
+
+        if (isValid)
+        {
+            showStep2 = true;
+            serverErrors.Clear();
+        }
+    }
+
+    private async Task OnDoctorOrDateChanged()
+    {
+        availabilityChecked = false;
+        serverErrors.Clear();
+
+        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
+        {
+            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
+                Model.Doctor, DateOnly.FromDateTime(Model.AppointmentDate.Value));
+        }
+        else
+        {
+            timeSlots = new();
+        }
+
+        Model.TimeSlot = string.Empty;
+    }
+
+    private async Task CheckAvailability()
+    {
+        serverErrors.Clear();
+        availabilityChecked = false;
+
+        if (string.IsNullOrEmpty(Model.Doctor) || !Model.AppointmentDate.HasValue
+            || string.IsNullOrEmpty(Model.TimeSlot) || string.IsNullOrWhiteSpace(Model.ReasonForVisit))
+        {
+            return;
+        }
+
+        if (Model.AppointmentDate.Value.Date <= DateTime.Today)
+        {
+            serverErrors["Date"] = "Date must be in the future";
+            return;
+        }
+
+        var errors = await AppointmentService.ValidatePatientAsync(
+            Model.Email,
+            Model.InsuranceProvider,
+            Model.Doctor,
+            Model.TimeSlot);
+
+        if (errors.Count > 0)
+        {
+            serverErrors = errors;
+        }
+        else
+        {
+            availabilityChecked = true;
+        }
+    }
+
+    private void HandleSubmit()
+    {
+        if (availabilityChecked)
+        {
+            bookingConfirmed = true;
+        }
+    }
+}
